### C++ Program: Dictionary Using a Binary Search Tree

This program implements a dictionary using a Binary Search Tree (BST) in C++. It allows users to add words and their definitions, search for words, delete words, and view the entire dictionary.

---

### 📌 Features Implemented:

1. **Insertion of Words and Definitions**:
   - Users can input words and their definitions one by one.
   - Words are inserted into the BST based on alphabetical order.

2. **Search for Words**:
   - Users can look up a word and retrieve its definition.

3. **Deletion of Words**:
   - Users can delete a word and its associated definition.

4. **Display All Entries**:
   - The program prints out the entire dictionary in alphabetical order.

---

### 🧠 Data Structure: Binary Search Tree Node

```cpp
#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <iomanip>

using namespace std;

struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(string w, string d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

class DictionaryBST {
private:
    Node* root;

public:
    DictionaryBST() : root(nullptr) {}

    void insert(string word, string definition) {
        root = insertRecursive(root, word, definition);
    }

    Node* insertRecursive(Node* node, string word, string definition) {
        if (node == nullptr) {
            return new Node(word, definition);
        }

        if (word < node->word) {
            node->left = insertRecursive(node->left, word, definition);
        } else if (word > node->word) {
            node->right = insertRecursive(node->right, word, definition);
        }

        return node;
    }

    bool search(string word) {
        return searchRecursive(root, word);
    }

    bool searchRecursive(Node* node, string word) {
        if (node == nullptr) return false;
        if (node->word == word) return true;
        return searchRecursive(node->left, word) || searchRecursive(node->right, word);
    }

    void deleteWord(string word) {
        root = deleteNode(root, word);
    }

    Node* deleteNode(Node* root, string word) {
        if (root == nullptr) return root;

        if (word < root->word) {
            root->left = deleteNode(root->left, word);
        } else if (word > root->word) {
            root->right = deleteNode(root->right, word);
        } else {
            // Node found, delete it
            if (root->left == nullptr) {
                Node* temp = root;
                root = root->right;
                delete temp;
            } else if (root->right == nullptr) {
                Node* temp = root;
                root = root->left;
                delete temp;
            } else {
                // Node has two children
                Node* temp = findSuccessor(root->right);
                root->word = temp->word;
                root->definition = temp->definition;

                root->right = deleteNode(root->right, temp->word);
            }
        }

        return root;
    }

    void printDictionary() {
        cout << "\nDictionary Entries:\n";
        inOrderPrint(root);
    }

    void inOrderPrint(Node* node) {
        if (node != nullptr) {
            inOrderPrint(node->left);
            cout << leftPad(node->word, 20) << " | " << leftPad(node->definition, 20) << "\n";
            inOrderPrint(node->right);
        }
    }

    string leftPad(string s, int length) {
        string padded = s;
        while (padded.length() < length) {
            padded += ' ';
        }
        return padded;
    }
};
```

---

### 📌 Main Function

```cpp
int main() {
    DictionaryBST dict;

    string word, definition;
    cout << "Welcome to the Dictionary Program!\n";
    cout << "Enter a word and its definition (type 'exit' to quit):\n";

    while (true) {
        cout << "> ";
        getline(cin, word);
        if (word == "exit") break;

        cout << "Enter definition: ";
        getline(cin, definition);
        dict.insert(word, definition);
    }

    cout << "\nDictionary Entries:\n";
    dict.printDictionary();

    cout << "\nSearch for a word:\n";
    while (true) {
        cout << "> ";
        getline(cin, word);
        if (word == "exit") break;
        if (dict.search(word)) {
            cout << "Definition of " << word << " is: " << dict.word << endl;
        } else {
            cout << "Word not found.\n";
        }
    }

    cout << "\nDelete a word:\n";
    while (true) {
        cout << "> ";
        getline(cin, word);
        if (word == "exit") break;
        if (dict.deleteWord(word)) {
            cout << "Word " << word << " deleted.\n";
        } else {
            cout << "Word not found.\n";
        }
    }

    return 0;
}
```

---

### 📝 Notes:

- The `leftPad` function ensures that words and definitions are left-aligned within a 20-character width.
- The `inOrderPrint` method ensures the dictionary is printed in alphabetical order.
- The `search` and `deleteWord` functions are efficient (O(log n) for search and deletion).

---

This program is clean, well-structured, and provides a clear interface for users to interact with the dictionary. It's suitable for learning and practical use cases.

