```cpp
#include <iostream>
#include <limits>
#include <stdexcept>

// Function to get a valid integer input from the user
int getValidIntegerInput() {
    int num;
    std::cout << "Enter the first number: ";
    std::cin >> num;
    // Check if the input is a valid integer
    if (std::cin.fail()) {
        std::cerr << "Error: Invalid input. Please enter a valid integer.\n";
        // Re-prompt the user until a valid input is received
        while (std::cin.fail()) {
            std::cout << "Error: Invalid input. Please enter a valid integer.\n";
            std::cin.clear(); // Clear error state
            std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n'); // Clear buffer
            std::cout << "Enter the first number: ";
        }
        return getValidIntegerInput(); // Recursively call to retry input
    }
    return num;
}

// Function to get a valid integer input from the user
int getSecondValidIntegerInput() {
    int num;
    std::cout << "Enter the second number: ";
    std::cin >> num;
    // Check if the input is a valid integer
    if (std::cin.fail()) {
        std::cerr << "Error: Invalid input. Please enter a valid integer.\n";
        // Re-prompt the user until a valid input is received
        while (std::cin.fail()) {
            std::cout << "Error: Invalid input. Please enter a valid integer.\n";
            std::cin.clear(); // Clear error state
            std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n'); // Clear buffer
            std::cout << "Enter the second number: ";
        }
        return getSecondValidIntegerInput(); // Recursively call to retry input
    }
    return num;
}

