### **4. Code Example (C# WinForms)**

```csharp
using System;
using System.Collections.Generic;
using System.Windows.Forms;

namespace GolfScorePro
{
    public partial class MainForm : Form
    {
        private List<Hole> holes = new List<Hole>();
        private GameStats stats = new GameStats();

        public MainForm()
        {
            InitializeComponent();
            LoadHoles();
            DisplayStats();
        }

        private void LoadHoles()
        {
            // Example: Add 10 holes with par and scores
            for (int i = 1; i <= 10; i++)
            {
                holes.Add(new Hole { HoleNumber = i, Par = 4, Score = 3 });
            }
        }

        private void DisplayStats()
        {
            // Update total stats
            stats.TotalHoles = holes.Count;
            stats.TotalScore = holes.Sum(h => h.Score);
            stats.AverageScore = stats.TotalScore / stats.TotalHoles;
            stats.BestScore = holes.Min(h => h.Score);
            stats.WorstScore = holes.Max(h => h.Score);

            // Update UI
            labelTotalHoles.Text = $"Total Holes: {stats.TotalHoles}";
            labelTotalScore.Text = $"Total Score: {stats.TotalScore}";
            labelAvgScore.Text = $"Average Score: {stats.AverageScore}";
