#### 3. **ParkingFinderPage Class**
This class handles the main UI and logic.

```dart
class ParkingFinderPage extends StatefulWidget {
  @override
  _ParkingFinderPageState createState() => _ParkingFinderPageState();
}

class _ParkingFinderPageState extends State<ParkingFinderPage> {
  final Location _location = Location();
  String _currentLocation = "Unknown";
  List<ParkingSpot> _parkingSpots = [];

  @override
  void initState() {
    super.initState();
    _getCurrentLocation();
    _fetchParkingSpots();
  }

  Future<void> _getCurrentLocation() async {
    bool serviceEnabled = await _location.isEnabled();
    if (!serviceEnabled) {
      // Request permission
      await _location.requestEnable();
    }

    final LocationData locationData = await _location.getLocation();
    setState(() {
      _currentLocation = locationData.latitude.toString() + "," + locationData.longitude.toString();
    });
  }

  Future<void> _fetchParkingSpots() async {
    final String location = _currentLocation;
