public class ImageFilterDownloader {

    public static void main(String[] args) {
        String imageUrl = "https://example.com/image.jpg"; // Replace with your image URL
        String outputFilePath = "processed_image.jpg";

        try {
            // Step 1: Download the image from the URL
            BufferedImage originalImage = downloadImageFromURL(imageUrl);

            // Step 2: Apply a grayscale filter
            BufferedImage filteredImage = applyGrayscaleFilter(originalImage);

            // Step 3: Save the filtered image to disk
            saveImageToFile(filteredImage, outputFilePath);

            System.out.println("Image has been processed and saved to: " + outputFilePath);

        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    private static BufferedImage downloadImageFromURL(String imageUrl) throws IOException {
        URL url = new URL(imageUrl);
        return ImageIO.read(url);
    }

    private static BufferedImage applyGrayscaleFilter(BufferedImage image) {
        int width = image.getWidth();
        int height = image.getHeight();

        BufferedImage filtered = new BufferedImage(width, height, BufferedImage.TYPE_BYTE_GRAY);

        for (int y = 0; y < height; y++) {
            for (int x = 0; x < width; x++) {
                int pixel = image.getRGB(x, y);
                int r = (pixel >> 16) & 0xFF;
                int g = (pixel >> 8) & 0xFF;
                int b = pixel & 0xFF;

                int gray = (r + g + b) / 3;
                filtered.setRGB(x, y, (gray << 16) | (gray << 8) | gray);
            }
        }

        return filtered;
    }

    private static void saveImageToFile(BufferedImage image, String outputPath) throws IOException {
        ImageIO.write(image, "jpg", new File(outputPath));
    }
}
```

