# Perl Script: Haversine Distance Calculation

This script calculates the distance between two points on Earth using the Haversine formula. It supports latitude and longitude input, and provides the distance in kilometers or miles based on the user's choice. The script also includes error handling and documentation.

```perl
#!/usr/bin/perl
use strict;
use warnings;
use Getopt::Long;
use URI::Escape;
use JSON;

# Configuration
my $default_unit = 'kilometers';
my $distance_unit = 'kilometers';
my $location_names = [];

# Haversine formula
sub haversine_distance {
    my ($lat1, $lon1, $lat2, $lon2, $unit) = @_;
    my $R = 6371; # Radius of the Earth in kilometers

    # Convert degrees to radians
    my $lat1_rad = deg2rad($lat1);
    my $lon1_rad = deg2rad($lon1);
    my $lat2_rad = deg2rad($lat2);
    my $lon2_rad = deg2rad($lon2);

    # Haversine formula
    my $a = (sin($lat2_rad - $lat1_rad) * sin($lat2_rad) + cos($lat1_rad) * cos($lat2_rad) * cos($lon2_rad - $lon1_rad));
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = $R * $c;

    # Convert to unit
    if ($unit eq 'miles') {
        $distance *= 0.621371;
    }

    return $distance;
}

# Convert degrees to radians
sub deg2rad {
    return ( $_[0] * pi() ) / 180;
}

# Get location names from JSON
sub get_location_names {
    my $json = '{"locations": [{"name": "Location A", "lat": 40.7128, "lon": -74.0060}, {"name": "Location B", "lat": 34.0522, "lon": -118.2437}]';
    my $locations = JSON::decode($json);
    return $locations->{'locations'};
}

# Error handling
sub handle_errors {
    my $error_message = "Error: ";
    if (!@_) {
        return $error_message . "No input provided.";
    }
    return $error_message . "Invalid input.";
}

# Main program
