my $unit = $default_unit;

# Parse command line options
GetOptions(
    'unit=s' => \$unit,
    'help' => \&help
);

# Check for help
if ($ARGV[0] eq '--help') {
    &help;
    exit;
}

# Parse input
my ($lat1, $lon1, $lat2, $lon2);
my ($loc1, $loc2);

# Parse latitude and longitude
if ($input =~ /^(\d+\.?\d*)\s+(\d+\.?\d*)\s+(\d+\.?\d*)\s+(\d+\.?\d*)/) {
    ($lat1, $lon1, $lat2, $lon2) = map { $_ } @_[0, 2, 4, 6];
    ($loc1, $loc2) = map { $_ } @_[1, 3];
} else {
