}

# Validate latitude and longitude ranges
if ($lat1 < -90 || $lat1 > 90 || $lon1 < -180 || $lon1 > 180 || $lat2 < -90 || $lat2 > 90 || $lon2 < -180 || $lon2 > 180) {
