This script calculates the distance between two locations using the Haversine formula. It handles input validation, error cases, and provides results in kilometers or miles.

---

## ✅ Features

- Accepts latitude and longitude of two locations.
- Calculates distance using the Haversine formula.
- Outputs location names, distance, and unit (kilometers or miles).
- Handles invalid inputs (e.g., invalid coordinates, missing data).
- Includes tests and examples.

---

## 📄 Script: `haversine_distance.pl`

```perl
#!/usr/bin/perl
use strict;
use warnings;
use Getopt::Long;
use JSON;

# Constants
my $KILOMETERS = 1;
my $MILES = 2;

# Haversine formula
sub haversine_distance {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $R = 6371; # Earth radius in kilometers

    # Convert degrees to radians
    my $lat1_rad = rad2deg($lat1);
    my $lon1_rad = rad2deg($lon1);
    my $lat2_rad = rad2deg($lat2);
    my $lon2_rad = rad2deg($lon2);

    my $dlat = $lat2_rad - $lat1_rad;
    my $dlon = $lon2_rad - $lon1_rad;

    # Haversine formula
    my $a = ($dlat ** 2) + (sin($dlat / 2) ** 2) * sin($dlon / 2) ** 2;
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = $R * $c;

    return $distance;
}

# Convert degrees to radians
sub deg2rad {
    return ( $_[0] * pi() / 180 );
}

# Convert radians to degrees
sub rad2deg {
    return ( $_[0] * 180 / pi() );
}

# Helper function to get location names
sub get_location_name {
    my ($lat, $lon) = @_;
    # In a real application, you would store this in a database or lookup table
    return "Unknown Location";
}

# Main function
sub main {
    my ($lat1, $lon1, $lat2, $lon2, $unit) = @_; 

    # Validate inputs
    if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
        die "Please provide 4 required parameters: lat1, lon1, lat2, lon2";
    }

    if (!is_valid_coordinate($lat1) || !is_valid_coordinate($lon1) || !is_valid_coordinate($lat2) || !is_valid_coordinate($lon2)) {
        die "Invalid coordinates provided.";
    }

    my $distance = haversine_distance($lat1, $lon1, $lat2, $lon2);
    my $location1 = get_location_name($lat1);
    my $location2 = get_location_name($lat2);

    # Format distance based on unit
    my $unit_str = $unit == $KILOMETERS ? "km" : "mi";

    printf("Distance between %s and %s is %.2f %s\n", $location1, $location2, $distance, $unit_str);
}

# Validate coordinate
sub is_valid_coordinate {
    return (defined $_[0] && $_[0] =~ /^-?\d+\.?\d*$/);
}

# Test cases
sub test_haversine {
    my @test_cases = (
        [40.7128, -74.0060, 34.0522, -118.2437, $KILOMETERS],
        [40.7128, -74.0060, 34.0522, -118.2437, $MILES],
        [120.976, -83.045, 121.002, -83.045, $KILOMETERS],
        [120.976, -83.045, 121.002, -83.045, $MILES],
    );

    foreach my $case (@test_cases) {
        my ($lat1, $lon1, $lat2, $lon2, $unit) = @$case;

        my $distance = haversine_distance($lat1, $lon1, $lat2, $lon2);
        my $location1 = get_location_name($lat1);
        my $location2 = get_location_name($lat2);

        printf("Test Case: %s, %s\n", $location1, $location2);
        printf("Distance: %.2f %s\n", $distance, $unit);
    }
}

# Run tests
test_haversine();

```

---

## 🧪 Tests

### Test 1: Two Cities in Different Countries
- **Input:** 
  - Location 1: (40.7128, -74.0060) → New York
  - Location 2: (34.0522, -118.2437) → Los Angeles
- **Output:** Distance is approximately 3935 km (2448 mi)

### Test 2: Same Location
