import Foundation

// Define the Node structure for the BST
struct Node {
    let value: Int
    let left: Node?
    let right: Node?

    init(value: Int) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// BST class to manage the tree
class BinarySearchTree {
    private var root: Node?

    // Insert a new node into the BST
    func insert(_ value: Int) {
        root = insertNode(root, value)
    }

    private func insertNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return Node(value: value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value)
        } else {
            node!.right = insertNode(node!.right, value)
        }

        return node!
    }

    // Delete a node from the BST
    func delete(_ value: Int) {
        root = deleteNode(root, value)
    }

    private func deleteNode(_ node: Node?, _ value: Int) -> Node? {
        guard let node = node else {
            return nil
        }

        if value < node!.value {
            node!.left = deleteNode(node!.left, value)
        } else if value > node!.value {
            node!.right = deleteNode(node!.right, value)
        } else {
            // Node found, delete it
            if node!.left == nil {
                return node!.right
            } else if node!.right == nil {
                return node!.left
            } else {
                // Find the inorder successor (right subtree's minimum)
                let successor = findInorderSuccessor(node!)
                node!.value = successor.value
                node!.right = deleteNode(node!.right, successor.value)
            }
        }

        return node
    }

    // Find the inorder successor (minimum in the right subtree)
    private func findInorderSuccessor(_ node: Node?) -> Node? {
        var current = node
        while current?.left != nil {
            current = current!.left
        }
        return current
    }

    // Traverse the tree in Pre-order
    func preOrderTraverse() {
        preOrderTraverse(root)
    }

    private func preOrderTraverse(_ node: Node?) {
        guard let node = node else { return }
        print("\(node.value) ", separator: " ")
        preOrderTraverse(node.left)
        preOrderTraverse(node.right)
    }

    // Traverse the tree in In-order
    func inOrderTraverse() {
        inOrderTraverse(root)
    }

    private func inOrderTraverse(_ node: Node?) {
        guard let node = node else { return }
        inOrderTraverse(node.left)
        print("\(node.value) ", separator: " ")
        inOrderTraverse(node.right)
    }

    // Traverse the tree in Post-order
    func postOrderTraverse() {
        postOrderTraverse(root)
    }

    private func postOrderTraverse(_ node: Node?) {
        guard let node = node else { return }
        postOrderTraverse(node.left)
        postOrderTraverse(node.right)
        print("\(node.value) ", separator: " ")
    }
}
```

### Explanation:
- **Node**: Represents a node in the BST with a value and pointers to its left and right children.
- **BinarySearchTree**: Manages the BST with root, insert, delete, and traversal methods.
- **Insert**: Adds a new node to the BST following the BST properties.
- **Delete**: Removes a node while maintaining BST properties.
- **Traversal**: 
  - **Pre-order**: Visit the node first, then left, then right.
  - **In-order**: Visit left, then the node, then right.
  - **Post-order**: Visit left, then right, then the node.

This implementation ensures efficient operations (O(log n) average case for insert/delete and O(n) in worst case for delete) and clear structure for understanding the BST behavior.

